    def test_delete_ind_onboarded_api_invoker(self):
        """Test case for delete_ind_onboarded_api_invoker

        Delete an existing Individual On-boarded API Invoker resource.
        """
        headers = { 
            'Accept': 'application/problem+json',
        }
        response = self.client.open(
            '/api-invoker-management/v1/onboardedInvokers/{onboarding_id}'.format(onboarding_id='onboarding_id_example'),
            method='DELETE',
            headers=headers)
        self.assert200(response,
                       'Response body is : ' + response.data.decode('utf-8'))

